/* eslint-disable */
/* Service worker — generated by scripts/build-sw.ts. Do not edit the output. */

const BUILD_ID = '__BUILD_ID__'
const CACHE_NAME = `service-ops-v${BUILD_ID}`
const PRECACHE_URLS = __PRECACHE_LIST__

const HASHED_ASSET_RE =
  /[-.][A-Za-z0-9_-]{8,}\.(?:js|mjs|css|woff2?|ttf|otf|eot|svg|png|jpe?g|webp|avif|gif|ico)$/

function isNetworkOnly(url) {
  if (url.host.includes('convex.cloud')) return true
  if (url.host.includes('better-auth')) return true
  if (url.pathname.startsWith('/api/')) return true
  return false
}

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches
      .open(CACHE_NAME)
      .then((cache) => cache.addAll(PRECACHE_URLS))
      .catch((err) => {
        console.warn('[sw] precache failed', err)
      }),
  )
})

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((keys) =>
        Promise.all(
          keys
            .filter((key) => key !== CACHE_NAME)
            .map((key) => caches.delete(key)),
        ),
      ),
  )
})

self.addEventListener('fetch', (event) => {
  const req = event.request
  if (req.method !== 'GET') return

  const url = new URL(req.url)

  if (url.origin !== self.location.origin) return
  if (isNetworkOnly(url)) return
  if (req.headers.has('Authorization')) return

  if (req.mode === 'navigate') {
    event.respondWith(
      fetch(req).catch(() =>
        caches
          .match('/offline.html')
          .then((res) => res || new Response('Offline', { status: 503 })),
      ),
    )
    return
  }

  if (HASHED_ASSET_RE.test(url.pathname)) {
    event.respondWith(
      caches.match(req).then((cached) => {
        if (cached) return cached
        return fetch(req).then((res) => {
          if (res && res.status === 200 && res.type === 'basic') {
            const clone = res.clone()
            caches
              .open(CACHE_NAME)
              .then((cache) => cache.put(req, clone))
              .catch(() => {})
          }
          return res
        })
      }),
    )
    return
  }

  // default: pass through (network-only, no caching)
})

// ────────────────────────────────────────────────────────────────────────────
// Web Push (Phase 6, bracket 1) — three notification types only:
//   - worker assigned (→ /dashboard/jobs/{id})
//   - client: worker accepted (→ /client/requests/{id})
//   - client: request completed (→ /client/requests/{id})
// Payload shape: { title, body, url, tag }
// ────────────────────────────────────────────────────────────────────────────

self.addEventListener('push', (event) => {
  /** @type {{ title?: string; body?: string; url?: string; tag?: string }} */
  let data = {}
  if (event.data) {
    try {
      data = event.data.json()
    } catch {
      data = { body: event.data.text() }
    }
  }
  const title = data.title || 'Service Ops'
  const options = {
    body: data.body || '',
    tag: data.tag,
    icon: '/icons/icon-192.png',
    badge: '/icons/icon-192.png',
    data: { url: data.url || '/' },
  }
  event.waitUntil(self.registration.showNotification(title, options))
})

self.addEventListener('notificationclick', (event) => {
  event.notification.close()
  const target = (event.notification.data && event.notification.data.url) || '/'
  event.waitUntil(
    self.clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then((windowClients) => {
        for (const client of windowClients) {
          try {
            const clientUrl = new URL(client.url)
            if (
              clientUrl.origin === self.location.origin &&
              'focus' in client
            ) {
              if ('navigate' in client) client.navigate(target)
              return client.focus()
            }
          } catch {}
        }
        if (self.clients.openWindow) return self.clients.openWindow(target)
        return undefined
      }),
  )
})
